 60→bool ULFPGameInstance::TryAddUnit(const FLFPUnitEntry& Unit)
 61→{
 62→	if (!Unit.IsValid()) return false;
 63→
 64→	if (!IsPartyFull())
 65→	{
 66→		PartyUnits.Add(Unit);
 67→		UE_LOG(LogTemp, Log, TEXT("单位 %s 加入出战队伍（%d/%d）"), *Unit.TypeID.ToString(), PartyUnits.Num(), MaxPartySize);
 68→		return true;
 69→	}
 70→	if (!IsReserveFull())
 71→	{
 72→		ReserveUnits.Add(Unit);
 73→		UE_LOG(LogTemp, Log, TEXT("单位 %s 加入备战营（%d/%d）"), *Unit.TypeID.ToString(), ReserveUnits.Num(), MaxReserveSize);
 74→		return true;
 75→	}
 76→	return false;
 77→}
