 81→void ALFPTurnManager::BeginNewRound()
 82→{
 83→    CurrentRound++;
 84→    bIsInRound = true;
 85→
 86→    // 重置所有单位
 87→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
 88→    {
 89→        if (Unit && Unit->IsValidLowLevel())
 90→        {
 91→            Unit->ResetForNewRound();
 92→        }
 93→    }
 94→
 95→    // 按速度排序单位
 96→    SortUnitsBySpeed();
 97→
 98→    // 清空上一轮的敌人计划
 99→    EnemyActionPlans.Empty();
100→    AllocatedSkills.Empty();
101→
102→    // 恢复阵营 AP
103→    for (auto& Pair : FactionCurrentAP)
104→    {
105→        Pair.Value = FMath::Min(Pair.Value + FactionAPRecovery, FactionMaxAP);
106→        OnFactionAPChanged.Broadcast(Pair.Key, Pair.Value);
107→    }
108→
109→    // 进入敌人规划阶段
110→    BeginEnemyPlanningPhase();
111→}
112→
113→void ALFPTurnManager::EndCurrentRound()
114→{
115→    bIsInRound = false;
116→
117→    SetPhase(EBattlePhase::BP_RoundEnd);
118→
119→    // 通知玩家本回合结束
120→    for (FConstPlayerControllerIterator It = GetWorld()->GetPlayerControllerIterator(); It; ++It)
121→    {
122→        if (ALFPTacticsPlayerController* PC = Cast<ALFPTacticsPlayerController>(*It))
123→        {
124→            PC->OnRoundEnded(CurrentRound);
125→        }
126→    }
127→
128→    // 添加延迟后开始新回合
129→    FTimerHandle TimerHandle;
130→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, this, &ALFPTurnManager::BeginNewRound, 0.5f, false);
131→}
